#include<bits/stdc++.h>using namespace std;int t,n,b[110],v[110],ans=0;void dfs(int x){    if(x==n+1){        ans++;        if(ans>n) return;        for(int i=1;i<=n;i++) cout<<b[i]<<' ';        cout<<endl;        return;    }    for(int i=1;i<=n;i++){        if(x==1){            v[i]=1;            b[x]=i;            dfs(x+1);            v[i]=0;        }else{            if(v[i]==0&&i!=b[x-1]+b[x-2]){                v[i]=1;                b[x]=i;                dfs(x+1);                v[i]=0;            }        }    }}int main(){    cin>>t;    while(t--){        cin>>n;        dfs(1);        ans=0;    }        return 0;}